487→func (sched *Scheduler) findNodesThatFitPod(ctx context.Context, schedFramework framework.Framework, state fwk.CycleState, pod *v1.Pod) ([]fwk.NodeInfo, framework.Diagnosis, string, fwk.PodSignature, error) {
   488→	logger := klog.FromContext(ctx)
   489→	diagnosis := framework.Diagnosis{
   490→		NodeToStatus: framework.NewDefaultNodeToStatus(),
   491→	}
   492→
   493→	allNodes, err := sched.nodeInfoSnapshot.NodeInfos().List()
   494→	if err != nil {
   495→		return nil, diagnosis, "", nil, err
   496→	}
   497→	// Run "prefilter" plugins.
   498→	preRes, s, unscheduledPlugins := schedFramework.RunPreFilterPlugins(ctx, state, pod)
   499→	diagnosis.UnschedulablePlugins = unscheduledPlugins
   500→	if !s.IsSuccess() {
   501→		if !s.IsRejected() {
   502→			return nil, diagnosis, "", nil, s.AsError()
   503→		}
   504→		// All nodes in NodeToStatus will have the same status so that they can be handled in the preemption.
   505→		diagnosis.NodeToStatus.SetAbsentNodesStatus(s)
   506→
   507→		// Record the messages from PreFilter in Diagnosis.PreFilterMsg.
   508→		msg := s.Message()
   509→		diagnosis.PreFilterMsg = msg
   510→		logger.V(5).Info("Status after running PreFilter plugins for pod", "pod", klog.KObj(pod), "status", msg)
   511→		diagnosis.AddPluginStatus(s)
   512→		return nil, diagnosis, "", nil, nil
   513→	}
   514→
   515→	var nodeHint string
   516→	var signature fwk.PodSignature
   517→	if utilfeature.DefaultFeatureGate.Enabled(features.OpportunisticBatching) {
   518→		// We get the node hint even if we have a nominated name for simplicity, but we could potentially avoid it
   519→		// in this scenario in the future.
   520→		nodeHint, signature = schedFramework.GetNodeHint(ctx, pod, state, sched.CurrentCycle())
   521→	}
   522→
   523→	// "NominatedNodeName" can potentially be set in a previous scheduling cycle as a result of preemption.
   524→	// This node is likely the only candidate that will fit the pod, and hence we try it first before iterating over all nodes.
   525→	// We take the same tack for hinted nodes from the batch module.
   526→	if len(pod.Status.NominatedNodeName) > 0 || len(nodeHint) > 0 {
   527→		feasibleNodes, err := sched.evaluateNominatedNode(ctx, pod, schedFramework, state, nodeHint, diagnosis)
   528→		if err != nil {
   529→			utilruntime.HandleErrorWithContext(ctx, err, "Evaluation failed on nominated node", "pod", klog.KObj(pod), "node", pod.Status.NominatedNodeName)
   530→		}
   531→		// Nominated node passes all the filters, scheduler is good to assign this node to the pod.
   532→		if len(feasibleNodes) != 0 {
   533→			return feasibleNodes, diagnosis, nodeHint, signature, nil
   534→		}
   535→	}
   536→
   537→	nodes := allNodes
   538→	if !preRes.AllNodes() {
   539→		nodes = make([]fwk.NodeInfo, 0, len(preRes.NodeNames))
   540→		for nodeName := range preRes.NodeNames {
   541→			// PreRes may return nodeName(s) which do not exist; we verify
   542→			// node exists in the Snapshot.
   543→			if nodeInfo, err := sched.nodeInfoSnapshot.Get(nodeName); err == nil {
   544→				nodes = append(nodes, nodeInfo)
   545→			}
   546→		}
   547→		diagnosis.NodeToStatus.SetAbsentNodesStatus(fwk.NewStatus(fwk.UnschedulableAndUnresolvable, fmt.Sprintf("node(s) didn't satisfy plugin(s) %v", sets.List(unscheduledPlugins))))
   548→	}
   549→	feasibleNodes, err := sched.findNodesThatPassFilters(ctx, schedFramework, state, pod, &diagnosis, nodes)
   550→	// always try to update the sched.nextStartNodeIndex regardless of whether an error has occurred
   551→	// this is helpful to make sure that all the nodes have a chance to be searched
   552→	processedNodes := len(feasibleNodes) + diagnosis.NodeToStatus.Len()
   553→	sched.nextStartNodeIndex = (sched.nextStartNodeIndex + processedNodes) % len(allNodes)
   554→	if err != nil {
   555→		return nil, diagnosis, nodeHint, signature, err
   556→	}
   557→
   558→	feasibleNodesAfterExtender, err := findNodesThatPassExtenders(ctx, sched.Extenders, pod, feasibleNodes, diagnosis.NodeToStatus)
   559→	if err != nil {
   560→		return nil, diagnosis, nodeHint, signature, err
   561→	}
   562→	if len(feasibleNodesAfterExtender) != len(feasibleNodes) {
   563→		// Extenders filtered out some nodes.
   564→		//
   565→		// Extender doesn't support any kind of requeueing feature like EnqueueExtensions in the scheduling framework.
   566→		// When Extenders reject some Nodes and the pod ends up being unschedulable,
   567→		// we put fwk.ExtenderName to pInfo.UnschedulablePlugins.
   568→		// This Pod will be requeued from unschedulable pod pool to activeQ/backoffQ
   569→		// by any kind of cluster events.
   570→		// https://github.com/kubernetes/kubernetes/issues/122019
   571→		if diagnosis.UnschedulablePlugins == nil {
   572→			diagnosis.UnschedulablePlugins = sets.New[string]()
   573→		}
   574→		diagnosis.UnschedulablePlugins.Insert(framework.ExtenderName)
   575→	}
   576→
   577→	return feasibleNodesAfterExtender, diagnosis, nodeHint, signature, nil
   578→}
